var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"조심하세요, 실키. 여긴 계단이 가파릅니다.","JPN":"気をつけてください、シルキー。ここの階段は急ですわ。","ENG":"Be careful Sylkie, the stairs here are steep.","TWN":"小心點，思琪。這裡的樓梯很陡。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"너무 어두워서 얼마나 내려왔는지도 모르겠어요.","JPN":"暗すぎて、どれくらい降りてきたかもわかりませんね。","ENG":"It's so dark, I can't see how far I've come down.","TWN":"太黑了，不知道往底下走了多少。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"총소리도…… 더는 들리지 않아요.","JPN":"銃声も……もう聞こえません。","ENG":"The gunshots... I don't hear them anymore.","TWN":"槍聲……也聽不見了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"이 지하에 부학회장님의 힘을 되찾을 방법이 있는 건가요?","JPN":"この地下に、副学会長様の力を取り戻す方法があるんですか？","ENG":"Is the basement where you're going to regain your powers, ma'am?","TWN":"這地下有能找回副學會長力量的辦法嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래요. 여기가 아니면 안 돼요.","JPN":"そうですわ。ここでないといけません。","ENG":"Yes, and this is the only place where I can.","TWN":"是的，只有這裡可以。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"생각해 보면 이상하지 않나요?","JPN":"考えてみたら、おかしくないですか？","ENG":"Do you not find it odd?","TWN":"想想不覺得奇怪嗎？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저는 갑자기 힘이 약해지는 바람에 학회원들 상대로도 쩔쩔 매는 처지였어요.","JPN":"私は突然力が弱まり、学会員の相手をするだけでも大変でした。","ENG":"I had become so weak that I could not even defend myself against the Society members.","TWN":"因為我的力量突然變弱，所以面對學會成員也手足無措。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데도 결국 힘을 되찾아야겠다는 생각은 전혀 안 했죠.","JPN":"それなのに力を取り戻そうとはまったく考えませんでしたわ。","ENG":"Nevertheless, I never thought to get my powers back.","TWN":"但即便如此，我還是完全沒想過要找回力量。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델을 찾아가는 와중에 무슨 일이 생길 줄 모르는데도 말입니다.","JPN":"エデルを訪ねていく途中でどんなことが起きるかもわからないのにです。","ENG":"Even though I did not know what would happen as I searched for Edel.","TWN":"即便在尋找艾瑟兒的過程中，我不知道會發生什麼事。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"어……?","JPN":"え……？","ENG":"Huh...?","TWN":"呃……？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그렇네요. 전 시간이 없어서 서두르신 줄 알았어요.","JPN":"そういえばそうですね。時間がないから急いでいるのかと思っていました。","ENG":"You're right. I assumed you were rushing because you didn't have time.","TWN":"是啊，我還以為是因為沒時間，你太著急了。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그럼… 왜 그러셨을까요?","JPN":"じゃあ……どうしてですか？","ENG":"Then... what was the real reason?","TWN":"那……為什麼會這樣呢？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사장님은 수도원에서 제 기억에 혼선이 일어났다고 하셨습니다.","JPN":"社長は修道院で、私の記憶が混乱しているとおっしゃいました。","ENG":"Boss informed me that my memories had become jumbled at the monastery.","TWN":"在修道院裡，老闆說我的記憶出現了混亂。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"심리적인 이유로, 무의식이 떠올리기를 거부한다는 추론이었죠.","JPN":"心理的な理由で、無意識に思い出すことを拒んでいるという推論でした。","ENG":"He assumed it was psychological, and my subconscious was refusing to recall them.","TWN":"他推斷我是因為心理上的原因，下意識地拒絕想起來。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"네. 회동에서 있었던 일 때문에 학회와 관련된 일은 떠올리기 싫어하신다고……","JPN":"はい。会合での出来事のせいで、学会に関することを思い出したくないと思っているって……","ENG":"Yes. He said something about you not wanting to remember what happened back at the meeting...","TWN":"是的。他說你因為會議的事，拒絕想起與學會有關的事……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"빈정 상해서 며칠 동안 방에 틀어박혀 있었죠.","JPN":"腹が立って、何日も部屋に引きこもっていましたわ。","ENG":"I was upset so I locked myself in my room for days on.","TWN":"因為傷心，我在房間裡待了好幾天。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"바꿔 말하면, 회동에서 실패한 건 저에게 그 정도였어요.","JPN":"言ってみれば、会合で失敗した件はその程度のことだったのです。","ENG":"In other words, the failure of the meeting was just that much to me.","TWN":"換句話說，在會議上失敗的事，對我來說只是那種程度而已。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"학회가 원래 광인들의 소굴이라는 사실은 알고 있었으니까요.","JPN":"学会がそもそも狂人の巣窟だってことはわかっていましたから。","ENG":"I already knew that the Society was full of lunatics.","TWN":"因為我知道學會本來就是一群瘋子的聚集地。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};